@startuml
left to right direction
skinparam classAttributeIconSize 0
skinparam class {
  BackgroundColor White
  ArrowColor Black
  BorderColor Black
  FontColor Black
}

class "ShoppingCart" as ShoppingCart {
  <<entity>>
  E
  /SubTotal : Currency
  /TaxAmount : Currency
  /DiscountAmount : Currency
  /TotalAmount : Currency
}

class "ProductOnCart" as ProductOnCart {
  <<entity>>
  E
  /Price : Currency
  Quantity : Integer
  /Total : Currency
}

class "Customer" as Customer {
  C
}

class "Product" as Product {
  C
}

ShoppingCart --|> ProductOnCart : 0..* ProductsOnCart
ProductOnCart --|> Product : 0..*
ShoppingCart --|> Customer : 1..1 Customer

@enduml
